import{_ as e,o as d,c as a,ag as o}from"./chunks/framework.DTiDeF2Q.js";const b=JSON.parse('{"title":"Псевдонимы редакторов | Dotfiles (RU)","titleTemplate":":title","description":"Псевдонимы оболочки для Neovim, VS Code, Vim, Nano, Emacs и Sublime Text. Редактируйте файлы быстрее с универсальными ярлыками.","frontmatter":{"title":"Псевдонимы редакторов | Dotfiles","description":"Псевдонимы оболочки для Neovim, VS Code, Vim, Nano, Emacs и Sublime Text. Редактируйте файлы быстрее с универсальными ярлыками.","lang":"ru-RU","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Псевдонимы редакторов preview","canonical":"/ru/aliases/editor/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Псевдонимы редакторов","pageType":"docs","schemaType":"WebPage","metaTitle":"Псевдонимы редакторов - Dotfiles (RU)","permalink":"/ru/aliases/editor/","sidebar":true,"meta":[{"name":"keywords","content":"editor aliases, neovim, vim, vscode, nano, emacs, sublime text, shell shortcuts, dotfiles"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Псевдонимы оболочки для Neovim, VS Code, Vim, Nano, Emacs и Sublime Text. Редактируйте файлы быстрее с универсальными ярлыками."},{"name":"twitter:title","content":"Псевдонимы редакторов - Dotfiles"},{"name":"og:title","content":"Псевдонимы редакторов - Dotfiles"},{"name":"og:description","content":"Псевдонимы оболочки для Neovim, VS Code, Vim, Nano, Emacs и Sublime Text. Редактируйте файлы быстрее с универсальными ярлыками."},{"name":"og:image:alt","content":"Dotfiles - Простой дизайн для вашей жизни в командной оболочке"},{"name":"og:locale","content":"ru_RU"}]},"headers":[],"relativePath":"ru/aliases/editor/index.md","filePath":"ru/aliases/editor/index.md","lastUpdated":1773010926000}'),r={name:"ru/aliases/editor/index.md"};function i(c,t,s,l,n,m){return d(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="псевдонимы-редакторов" tabindex="-1">Псевдонимы редакторов <a class="header-anchor" href="#псевдонимы-редакторов" aria-label="Permalink to &quot;Псевдонимы редакторов&quot;">​</a></h1><p>Ярлыки для запуска и настройки предпочитаемого текстового редактора.</p><p><img src="https://kura.pro/dotfiles/v2/images/titles/title-dotfiles.svg" alt="Баннер Dotfiles" title="Баннер Dotfiles"></p><h2 id="обзор" tabindex="-1">Обзор <a class="header-anchor" href="#обзор" aria-label="Permalink to &quot;Обзор&quot;">​</a></h2><p>Псевдонимы редакторов предоставляют единый интерфейс для редактирования текста в различных приложениях. Определённые в <code>editor.aliases.sh</code> и автоматически загружаемые chezmoi, эти ярлыки работают совместно с <code>editor.sh</code> для определения и настройки лучшего доступного редактора в вашей системе.</p><p>Система поддерживает Neovim, Visual Studio Code, Vim, Nano, Emacs, Sublime Text и Atom. Универсальные псевдонимы адаптируются к активному редактору, а специализированные псевдонимы предлагают функциональность для конкретного редактора.</p><h2 id="справочник" tabindex="-1">Справочник <a class="header-anchor" href="#справочник" aria-label="Permalink to &quot;Справочник&quot;">​</a></h2><h3 id="универсальные-псевдонимы" tabindex="-1">Универсальные псевдонимы <a class="header-anchor" href="#универсальные-псевдонимы" aria-label="Permalink to &quot;Универсальные псевдонимы&quot;">​</a></h3><p>Эти псевдонимы работают с любым редактором, настроенным через <code>editor.sh</code>.</p><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Описание</th></tr></thead><tbody><tr><td><code>e</code></td><td>Быстрая команда редактирования</td></tr><tr><td><code>edit</code></td><td>Стандартная команда редактирования</td></tr><tr><td><code>editor</code></td><td>Полная команда редактора</td></tr><tr><td><code>mate</code></td><td>Команда в стиле TextMate</td></tr><tr><td><code>n</code></td><td>Короткий псевдоним редактирования</td></tr><tr><td><code>v</code></td><td>Псевдоним редактирования в стиле Vim</td></tr></tbody></table><h3 id="псевдонимы-neovim" tabindex="-1">Псевдонимы Neovim <a class="header-anchor" href="#псевдонимы-neovim" aria-label="Permalink to &quot;Псевдонимы Neovim&quot;">​</a></h3><p>Доступны, когда Neovim является основным редактором.</p><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Описание</th></tr></thead><tbody><tr><td><code>vi</code></td><td>Перенаправлен на Neovim</td></tr><tr><td><code>vim</code></td><td>Перенаправлен на Neovim</td></tr><tr><td><code>nvimrc</code></td><td>Редактировать конфигурацию Neovim Vimscript</td></tr><tr><td><code>nvimlua</code></td><td>Редактировать конфигурацию Neovim Lua</td></tr><tr><td><code>nvimconf</code></td><td>Открыть директорию конфигурации Neovim</td></tr></tbody></table><h3 id="псевдонимы-visual-studio-code" tabindex="-1">Псевдонимы Visual Studio Code <a class="header-anchor" href="#псевдонимы-visual-studio-code" aria-label="Permalink to &quot;Псевдонимы Visual Studio Code&quot;">​</a></h3><p>Доступны, когда установлен VS Code.</p><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Описание</th></tr></thead><tbody><tr><td><code>vsc</code></td><td>Запустить VS Code</td></tr><tr><td><code>vsca</code></td><td>Добавить папку в текущее окно</td></tr><tr><td><code>vscd</code></td><td>Сравнить два файла</td></tr><tr><td><code>vscn</code></td><td>Открыть новое окно</td></tr><tr><td><code>vscr</code></td><td>Переиспользовать окно при открытии файлов</td></tr><tr><td><code>vscex</code></td><td>Установить расширение VS Code</td></tr><tr><td><code>vsclist</code></td><td>Показать установленные расширения</td></tr></tbody></table><h3 id="псевдонимы-vim" tabindex="-1">Псевдонимы Vim <a class="header-anchor" href="#псевдонимы-vim" aria-label="Permalink to &quot;Псевдонимы Vim&quot;">​</a></h3><p>Доступны, когда Vim является основным редактором.</p><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Описание</th></tr></thead><tbody><tr><td><code>vi</code></td><td>Перенаправлен на Vim</td></tr><tr><td><code>vimrc</code></td><td>Редактировать файл конфигурации Vim</td></tr><tr><td><code>vimconf</code></td><td>Открыть директорию конфигурации Vim</td></tr></tbody></table><h3 id="псевдонимы-nano" tabindex="-1">Псевдонимы Nano <a class="header-anchor" href="#псевдонимы-nano" aria-label="Permalink to &quot;Псевдонимы Nano&quot;">​</a></h3><p>Доступны, когда Nano является основным редактором.</p><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Описание</th></tr></thead><tbody><tr><td><code>nanorc</code></td><td>Редактировать файл конфигурации Nano</td></tr><tr><td><code>ne</code></td><td>Улучшенный Nano с номерами строк и плавной прокруткой</td></tr></tbody></table><h3 id="псевдонимы-emacs" tabindex="-1">Псевдонимы Emacs <a class="header-anchor" href="#псевдонимы-emacs" aria-label="Permalink to &quot;Псевдонимы Emacs&quot;">​</a></h3><p>Доступны, когда установлен Emacs.</p><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Описание</th></tr></thead><tbody><tr><td><code>em</code></td><td>Запустить Emacs</td></tr><tr><td><code>emacs-nw</code></td><td>Запустить Emacs в терминальном режиме</td></tr><tr><td><code>emacsc</code></td><td>Запустить клиент Emacs</td></tr><tr><td><code>emacsrc</code></td><td>Редактировать файл конфигурации Emacs</td></tr><tr><td><code>et</code></td><td>Быстрый терминальный Emacs</td></tr></tbody></table><h3 id="псевдонимы-sublime-text" tabindex="-1">Псевдонимы Sublime Text <a class="header-anchor" href="#псевдонимы-sublime-text" aria-label="Permalink to &quot;Псевдонимы Sublime Text&quot;">​</a></h3><p>Доступны, когда установлен Sublime Text.</p><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Описание</th></tr></thead><tbody><tr><td><code>st</code></td><td>Запустить Sublime Text</td></tr><tr><td><code>stt</code></td><td>Открыть текущую директорию в Sublime Text</td></tr><tr><td><code>stn</code></td><td>Открыть в новом окне Sublime Text</td></tr></tbody></table>',28)])])}const u=e(r,[["render",i]]);export{b as __pageData,u as default};
